var import_obsidian2 = require("obsidian");
var TodoExporter = class {
  constructor(app, settings, todoIndex) {
    this.app = app;
    this.settings = settings;
    this.todoIndex = todoIndex;
  }
  updateSettings(settings) {
    this.settings = settings;
  }
  /**
   * Export everything: todos to all README.md files + recent files to root README.
   */
  async exportAll() {
    let count = 0;
    count += await this.exportTodosForPerson("Me");
    const members = getTeamMembers(this.app, this.settings);
    for (const member of members) {
      count += await this.exportTodosForPerson(member.name);
    }
    count += await this.exportTodosForFolders();
    await this.exportRecentFiles();
    new import_obsidian2.Notice(`NotePack: Exported todos to ${count} README file(s)`);
  }
  /**
   * Export todos assigned to a person into their README.md.
   * "Me" writes to the vault root README.md.
   * Named persons write to Team/<Name>/README.md.
   */
  async exportTodosForPerson(assignedTo) {
    let readmePath;
    if (assignedTo.toLowerCase() === "me") {
      readmePath = "README.md";
    } else {
      readmePath = `${this.settings.teamFolder}/${assignedTo}/README.md`;
    }
    const todos = assignedTo.toLowerCase() === "me" ? this.todoIndex.getMyTodos() : this.todoIndex.getTodosFor(assignedTo);
    return await this.writeTodosToReadme(readmePath, todos) ? 1 : 0;
  }
  /**
   * Recursively find all README.md files in base folders and write
   * folder-scoped todos into each one.
   */
  async exportTodosForFolders() {
    let count = 0;
    for (const baseFolder of this.settings.baseFolders) {
      count += await this.exportFolderRecursive(baseFolder);
    }
    return count;
  }
  async exportFolderRecursive(folderPath) {
    const folder = this.app.vault.getAbstractFileByPath(folderPath);
    if (!(folder instanceof import_obsidian2.TFolder))
      return 0;
    let count = 0;
    for (const child of folder.children) {
      if (!(child instanceof import_obsidian2.TFolder))
        continue;
      if (child.path.toLowerCase().includes("archive"))
        continue;
      if (child.path.startsWith(this.settings.teamFolder + "/"))
        continue;
      const readmePath = `${child.path}/README.md`;
      const readmeFile = this.app.vault.getAbstractFileByPath(readmePath);
      if (readmeFile instanceof import_obsidian2.TFile) {
        const todos = this.todoIndex.getTodosInFolder(child.path);
        if (await this.writeTodosToReadme(readmePath, todos)) {
          count++;
        }
      }
      count += await this.exportFolderRecursive(child.path);
    }
    return count;
  }
  /**
   * Write recent files into the root README.md.
   */
  async exportRecentFiles() {
    const readmePath = "README.md";
    const readmeFile = this.app.vault.getAbstractFileByPath(readmePath);
    if (!(readmeFile instanceof import_obsidian2.TFile))
      return;
    const recentFiles = this.getRecentFiles();
    const anchor = `${this.settings.anchorHeadingLevel} ${this.settings.recentFilesAnchorTitle}`;
    const recentSection = recentFiles.map((f) => {
      const relativePath = f.path;
      const encoded = encodeURIComponent(relativePath).replace(/%2F/g, "/").replace(/%3A/g, ":").replace(/%2B/g, "+").replace(/%2C/g, ",");
      return `* [${f.name}](${encoded})`;
    }).join("\n");
    const content = `${anchor}
${recentSection}
`;
    let src = await this.app.vault.read(readmeFile);
    src = this.replaceSectionInSource(src, anchor, content);
    await this.app.vault.modify(readmeFile, src);
  }
  /**
   * Get the N most recently modified markdown files in the base folders.
   */
  getRecentFiles() {
    const allFiles = this.app.vault.getMarkdownFiles();
    return allFiles.filter((f) => {
      if (f.name === "README.md")
        return false;
      if (f.path.toLowerCase().includes("archive"))
        return false;
      if (this.settings.baseFolders.length === 0)
        return true;
      return this.settings.baseFolders.some(
        (base) => f.path.startsWith(base + "/") || f.path.startsWith(base)
      );
    }).sort((a, b) => b.stat.mtime - a.stat.mtime).slice(0, this.settings.recentFilesCount);
  }
  /**
   * Write a set of todos into a README.md file, replacing the todo section.
   */
  async writeTodosToReadme(readmePath, todos) {
    const file = this.app.vault.getAbstractFileByPath(readmePath);
    if (!(file instanceof import_obsidian2.TFile))
      return false;
    const anchor = `${this.settings.anchorHeadingLevel} ${this.settings.todoAnchorTitle}`;
    const todosContent = this.buildGroupedTodosString(todos, readmePath, anchor);
    let src = await this.app.vault.read(file);
    src = this.replaceSectionInSource(src, anchor, todosContent);
    await this.app.vault.modify(file, src);
    return true;
  }
  /**
   * Build the grouped todos markdown string for a README.md file.
   */
  buildGroupedTodosString(todos, readmePath, prefix) {
    const groupNames = this.todoIndex.getGroupNames(todos);
    let result = `${prefix}
`;
    for (const group of groupNames) {
      const groupTodos = todos.filter((t) => t.groupName === group).sort((a, b) => a.id - b.id);
      if (groupTodos.length === 0)
        continue;
      const firstTodo = groupTodos[0];
      const relativePath = this.relativeEncodedPath(
        readmePath,
        firstTodo.file.path
      );
      result += `
${this.settings.todoGroupHeadingLevel} [${group}](${relativePath})
`;
      for (const todo of groupTodos) {
        result += `- [ ] ${todo.text}
`;
      }
    }
    return result;
  }
  /**
   * Replace a heading section in a source string.
   * If the anchor doesn't exist, appends to the end.
   */
  replaceSectionInSource(src, anchor, newContent) {
    const headingLevel = this.settings.anchorHeadingLevel;
    const start = src.indexOf(anchor);
    if (start === -1) {
      return src.trimEnd() + "\n\n" + newContent.trimEnd() + "\n";
    }
    const afterAnchor = src.substring(start + anchor.length);
    const nextHeadingMatch = afterAnchor.indexOf(`
${headingLevel} `);
    const end = nextHeadingMatch === -1 ? src.length : start + anchor.length + nextHeadingMatch;
    const before = src.substring(0, start).trimEnd();
    const after = src.substring(end).trimStart();
    const parts = [before, newContent.trimEnd()];
    if (after)
      parts.push(after);
    return parts.join("\n\n") + "\n";
  }
  /**
   * Build a relative, URI-encoded path from one file to another.
   */
  relativeEncodedPath(fromPath, toPath) {
    const fromDir = fromPath.substring(0, fromPath.lastIndexOf("/")) || ".";
    const fromParts = fromDir === "." ? [] : fromDir.split("/");
    const toParts = toPath.split("/");
    let common = 0;
    while (common < fromParts.length && common < toParts.length && fromParts[common] === toParts[common]) {
      common++;
    }
    const ups = fromParts.length - common;
    const relative = [
      ...Array(ups).fill(".."),
      ...toParts.slice(common)
    ].join("/");
    return encodeURIComponent(relative).replace(/%2F/g, "/").replace(/%3A/g, ":").replace(/%2B/g, "+").replace(/%2C/g, ",");
  }
};

