      (text) => text.setPlaceholder("Recent Files").setValue(this.plugin.settings.recentFilesAnchorTitle).onChange(async (value) => {
        this.plugin.settings.recentFilesAnchorTitle = value.trim();
        await this.plugin.saveSettings();
      })
